import { Injectable } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { Book, BookDocument } from './book.schema';

@Injectable()
export class BookService {
  constructor(@InjectModel(Book.name) private model: Model<BookDocument>) {}

  async findAll(): Promise<Book[]> {
    return this.model.find().exec();
  }

  async findOne(id: string): Promise<Book> {
    const book = await this.model.findById(id).exec();
    if (!book) {
      throw new NotFoundException(`Book with id ${id} not found`);
    }
    return book;
  }

  async create(dto: any): Promise<Book> {
    return new this.model(dto).save();
  }

  async update(id: string, dto: any): Promise<Book> {
    const updatedBook = await this.model.findByIdAndUpdate(id, { $set: dto }, { new: true }).exec();
    if (!updatedBook) {
      throw new NotFoundException(`Book with id ${id} not found`);
    }
    return updatedBook;
  }

  async remove(id: string): Promise<Book> {
    const deletedBook = await this.model.findByIdAndDelete(id).exec();
    if (!deletedBook) {
      throw new NotFoundException(`Book with id ${id} not found`);
    }
    return deletedBook;
  }
}

